+    #[inline]
+    fn call(&self, req: Request) -> Response {
+        let (t1, t2, t3) = match extract_arg_3::<T1, T2, T3>(req) {
+            Ok(v) => v,
+            Err(resp) => return resp,
+        };
+        (self.func)(t1, t2, t3).into_response()
